      'mail',
      'mail-templates',
      'reset-password.hbs',
    ),
    context: {
      title: resetPasswordTitle,
      url: url.toString(),
      actionTitle: resetPasswordTitle,
      app_name: this.configService.get('app.name', { infer: true }),
      text1,
      text2,
      text3,
      text4,
    },
  });
}
```

